SELECT id, user_id, name, os_type, status, last_seen, created_at, agent_id
FROM nodes
WHERE id = #{id}

SELECT id, user_id, name, os_type, status, last_seen, created_at, agent_id
FROM nodes
WHERE user_id = #{userId} AND name = #{name}

SELECT id, user_id, name, os_type, status, last_seen, created_at, agent_id
FROM nodes
WHERE agent_id = #{agentId}

mapper.update:
UPDATE nodes
SET status = #{status}
WHERE id = #{id}
  AND status <> 'D'

UPDATE nodes
SET status = 'D'
WHERE id = #{id}
